      var leftText = rawText;
      var rightText = '';
      var idx = rawText.indexOf('[OS]');
      if (idx !== -1) {
        leftText = rawText.substring(0, idx).trim();
        rightText = rawText.substring(idx + 4).trim();
      }
      document.getElementById('leftDisplay').textContent = leftText;
      document.getElementById('rightDisplay').textContent = rightText;

      var body = document.body;
      var leftCard = document.getElementById('leftCard'), leftHeader = document.getElementById('leftHeader'), leftContent = document.getElementById('leftContent'), leftExpanded = true;
      var rightCard = document.getElementById('rightCard'), rightHeader = document.getElementById('rightHeader'), rightContent = document.getElementById('rightContent'), rightExpanded = true;
      var themeToggleBtn = document.getElementById('themeToggleBtn');

      function toggleCard(card,content,header,isExp,setExp){
        return function(e){
          if(e)e.stopPropagation();
          if(isExp()){ card.classList.remove('expanded'); content.style.maxHeight='0'; setExp(false); header.setAttribute('aria-expanded','false'); }
          else { card.classList.add('expanded'); content.style.maxHeight=content.scrollHeight+'px'; setExp(true); header.setAttribute('aria-expanded','true'); }
        };
      }
      leftHeader.addEventListener('click',toggleCard(leftCard,leftContent,leftHeader,function(){return leftExpanded;},function(v){leftExpanded=v;}));
      rightHeader.addEventListener('click',toggleCard(rightCard,rightContent,rightHeader,function(){return rightExpanded;},function(v){rightExpanded=v;}));

      function applyTheme(t){
        if(t==='light'){ body.classList.add('light-theme');body.classList.remove('dark-theme');try{localStorage.setItem('fox-preset-theme','light');}catch(e){} }
        else { body.classList.remove('light-theme');body.classList.add('dark-theme');try{localStorage.setItem('fox-preset-theme','dark');}catch(e){} }
      }
      var st=null;try{st=localStorage.getItem('fox-preset-theme');}catch(e){}
      if(st==='light'||st==='day')applyTheme('light');else if(st==='dark'||st==='night')applyTheme('dark');else applyTheme('dark');
      themeToggleBtn.addEventListener('click',function(e){e.stopPropagation();if(body.classList.contains('light-theme'))applyTheme('dark');else applyTheme('light');});

      function rr(a,b){return a+Math.random()*(b-a);}
      function spawnParticles(container){
        for(var i=0;i<15;i++){
          var dot=document.createElement('div');
          dot.className='ax-p particle-dot';
          var size=rr(1.5,4);
          dot.style.width=size+'px';dot.style.height=size+'px';
          dot.style.left=rr(5,90)+'%';dot.style.top=rr(10,85)+'%';
          dot.style.setProperty('--pdur',rr(6,14)+'s');
          dot.style.setProperty('--pdel',-(Math.random()*14)+'s');
          dot.style.setProperty('--pdx',rr(-6,6)+'px');
          dot.style.setProperty('--popeak',rr(0.25,0.55).toFixed(2));
          container.appendChild(dot);
        }
        for(var j=0;j<5;j++){
          var line=document.createElement('div');
          line.className='ax-p particle-line';
          line.style.height=rr(20,60)+'px';
          line.style.left=rr(8,88)+'%';line.style.top=rr(10,80)+'%';
          line.style.setProperty('--pdur',rr(8,16)+'s');
          line.style.setProperty('--pdel',-(Math.random()*16)+'s');
          line.style.setProperty('--popeak',rr(0.2,0.45).toFixed(2));
          container.appendChild(line);
        }
      }
      spawnParticles(document.getElementById('leftParticles'));
      spawnParticles(document.getElementById('rightParticles'));

      // ★ 默认展开
      setTimeout(function(){
        leftContent.style.maxHeight = leftContent.scrollHeight + 'px';
        rightContent.style.maxHeight = rightContent.scrollHeight + 'px';
      }, 80);
    })();
