    <div class="cat-header" onclick="toggleCollapsible()" tabindex="0" role="button" aria-expanded="false">
      <div class="cat-title">
        <img src="https://files.catbox.moe/6bjhoo.png" alt="狐神抚" class="cat-title-icon">
        吾乃狐神抚...
      </div>
      <div class="header-actions">
        <button class="theme-toggle-btn" id="themeToggleBtn" onclick="toggleTheme(event)" title="切换日夜模式" aria-label="切换日夜模式">🦊</button>
