  <script>
    (function () {
      const catIconUrls = [
        'https://i.postimg.cc/wM5fdRwD/retouch-2025082000312081.png',
        'https://i.postimg.cc/25JXdDqL/retouch-2025082002164365.png',
        'https://i.postimg.cc/hjdZp5xy/retouch-2025082002164425.png',
        'https://i.postimg.cc/gjbS5HHY/retouch-2025082002164465.png',
        'https://i.postimg.cc/fR8PLXDK/retouch-2025082002164500.png',
        'https://i.postimg.cc/Qxrwnhfp/retouch-2025082002164543.png',
        'https://i.postimg.cc/3wWcDRwH/retouch-2025082002164571.png',
        'https://i.postimg.cc/RCt2RNLS/retouch-2025082002164601.png',
        'https://i.postimg.cc/c4Mjp2zP/retouch-2025082002164624.png',
        'https://i.postimg.cc/4xfMswky/retouch-2025082002164656.png',
      ];

      const catIconElement = document.querySelector('.cat-title-icon');
      const collapsible = document.getElementById('catCollapsible');
      const content = collapsible.querySelector('.cat-content');
      const themeToggleBtn = document.getElementById('themeToggleBtn');
      const particleLayer = document.getElementById('particleLayer');
      let isExpanded = false;

      const savedTheme = localStorage.getItem('fox-preset-theme');
      if (savedTheme === 'dark' || savedTheme === 'night') {
        document.body.classList.add('night-mode');
        themeToggleBtn.textContent = '🐾';
      } else {
        themeToggleBtn.textContent = '🦊';
      }

      function setRandomIcon() {
        if (!catIconElement) return;
        const randomIndex = Math.floor(Math.random() * catIconUrls.length);
        const newIconUrl = catIconUrls[randomIndex];
        catIconElement.style.opacity = '0';
        setTimeout(() => {
          catIconElement.src = newIconUrl;
          requestAnimationFrame(() => {
            catIconElement.style.opacity = '1';
          });
        }, 80);
      }

      window.toggleTheme = function (event) {
        if (event) {
          event.stopPropagation();
          event.preventDefault();
        }
        const isNight = document.body.classList.toggle('night-mode');
        if (isNight) {
          themeToggleBtn.textContent = '🐾';
          localStorage.setItem('fox-preset-theme', 'dark');
        } else {
          themeToggleBtn.textContent = '🦊';
          localStorage.setItem('fox-preset-theme', 'light');
        }
      };

      window.toggleCollapsible = function () {
        if (isExpanded) {
          collapsible.classList.remove('expanded');
          content.style.maxHeight = '0';
          isExpanded = false;
          collapsible.querySelector('.cat-header').setAttribute('aria-expanded', 'false');
        } else {
          setRandomIcon();
          collapsible.classList.add('expanded');
          content.style.maxHeight = content.scrollHeight + 'px';
          isExpanded = true;
          collapsible.querySelector('.cat-header').setAttribute('aria-expanded', 'true');
        }
      };

      // 粒子（只有14个，不卡）
      function rr(a, b) { return a + Math.random() * (b - a); }
      const configs = [
        { cls: 'gd', n: 10, w: [2, 6], h: [2, 6], dur: [4, 9] },
        { cls: 'lr', n: 4, w: [1, 1], h: [35, 75], dur: [5, 10] }
      ];
      for (let gi = 0; gi < configs.length; gi++) {
        const g = configs[gi];
        for (let pi = 0; pi < g.n; pi++) {
          const p = document.createElement('div');
          p.className = 'ax-p ' + g.cls;
          p.style.width = rr(g.w[0], g.w[1]) + 'px';
          p.style.height = rr(g.h[0], g.h[1]) + 'px';
          p.style.left = (Math.random() * 90 + 5) + '%';
          p.style.top = (Math.random() * 90 + 5) + '%';
          if (g.cls === 'gd') {
            p.style.borderRadius = '50%';
            p.style.background = 'radial-gradient(circle, var(--particle-gold), rgba(195, 175, 108, 0.1), transparent)';
            p.style.animation = 'ascParticle ' + rr(g.dur[0], g.dur[1]) + 's ease-in-out infinite';
          } else {
            p.style.background = 'linear-gradient(180deg, var(--particle-line), rgba(220, 200, 128, 0.06), transparent)';
            p.style.animation = 'pulseVertical ' + rr(g.dur[0], g.dur[1]) + 's ease-in-out infinite';
            p.style.transformOrigin = 'top center';
          }
          p.style.animationDelay = -(Math.random() * 35) + 's';
          p.style.setProperty('--po', (0.15 + Math.random() * 0.2).toFixed(2));
          particleLayer.appendChild(p);
        }
      }

      // 默认折叠
      content.style.maxHeight = '0';
      collapsible.querySelector('.cat-header').setAttribute('aria-expanded', 'false');
      setRandomIcon();

      const footerToggle = document.querySelector('.cat-footer-toggle');
      if (footerToggle) {
        footerToggle.addEventListener('click', function (e) {
          e.stopPropagation();
          window.toggleCollapsible();
        });
      }

      document.addEventListener('keydown', function (event) {
        if (event.key === 'Enter' || event.key === ' ') {
          const activeElement = document.activeElement;
          if (activeElement && activeElement.classList.contains('cat-header')) {
            event.preventDefault();
            window.toggleCollapsible();
          }
        }
      });

      window.addEventListener('resize', function () {
        if (isExpanded) {
          content.style.maxHeight = content.scrollHeight + 'px';
        }
      });

        if (window.parent && window.parent !== window) {
          const observer = new ResizeObserver(() => {
            window.parent.postMessage({ type: 'resizeIframe', height: document.body.scrollHeight }, '*');
          });
          observer.observe(document.body);
        }
    })();
  </script>
</body>
