// ============================================
// 🌊 思维链平滑流式（全内存版）
// 支持：狐神抚/简约黑 × 收起/展开，样式与展开独立切换
// 兼容：搜索引擎插件（通过 __searchEngineBusy 标记跳过分析生成）
// ============================================

(function() {
    'use strict';

    // ==================== 配置 ====================
    const CONFIG = {
        // 思维链美化正则 ID
        HUSHE_ID: 'e0e42866-e292-497f-90e7-12ca32b0002f',
        HUSHE_EXPANDED_ID: '5a032062-5c07-4720-9af9-4c473bd2456a',
        JIANYUE_ID: 'd647dce9-e91c-40c0-ac41-0587745fc26f',
        JIANYUE_EXPANDED_ID: '76180750-d8c6-43e3-8b69-72786973cd4e',
        BIAOLI_ID: '958b9724-25b5-41e0-9999-9279b4cc6159',
        BIAOLI_EXPANDED_ID: 'd51b8791-c839-4f33-8e12-e81ba0cd27be',

        // 思维链隐藏正则 ID
        HIDE_ID: '0a049bd9-5bc3-4c72-a733-702f04749b71',

        // 延迟时间（毫秒）
        INIT_DELAY: 4000,
        HIDE_DELAY: 500,
        RESTORE_DELAY: 200,

        // 存储键
        STYLE_KEY: 'SPreset_ThoughtChain_Style',
        EXPAND_KEY: 'SPreset_ThoughtChain_Expand',
        ENABLED_KEY: 'smoothStream_enabled',
    };

    // ==================== 状态 ====================
    const state = {
        enabled: false,
        currentStyle: localStorage.getItem(CONFIG.STYLE_KEY) || 'HUSHE',
        isExpanded: localStorage.getItem(CONFIG.EXPAND_KEY) !== 'false',  // 默认展开
        isGenerating: false,
        eventHandles: [],
    };

    // ==================== 样式 ID 映射 ====================
    function getStyleId(style, expanded) {
        if (style === 'HUSHE') return expanded ? CONFIG.HUSHE_EXPANDED_ID : CONFIG.HUSHE_ID;
        if (style === 'JIANYUE') return expanded ? CONFIG.JIANYUE_EXPANDED_ID : CONFIG.JIANYUE_ID;
        if (style === 'BIAOLI') return expanded ? CONFIG.BIAOLI_EXPANDED_ID : CONFIG.BIAOLI_ID;
        return expanded ? CONFIG.HUSHE_EXPANDED_ID : CONFIG.HUSHE_ID; // 默认回退
    }

    const ALL_STYLE_IDS = [
        CONFIG.HUSHE_ID, CONFIG.HUSHE_EXPANDED_ID,
        CONFIG.JIANYUE_ID, CONFIG.JIANYUE_EXPANDED_ID,
        CONFIG.BIAOLI_ID, CONFIG.BIAOLI_EXPANDED_ID,
    ];

    // ==================== 工具函数 ====================

    function log(...args) {
        const time = new Date().toISOString().split('T')[1].split('.')[0];
        console.log('[🌊平滑流式]', time, ...args);
    }

    function getRegexes() {
        return SillyTavern.getContext?.()?.chatCompletionSettings?.extensions?.regex_scripts;
    }

    function updateMemory(updater) {
        const regexes = getRegexes();
        if (!regexes) return false;
        updater(regexes);
        return true;
    }

    function isThoughtVisible() {
        const hideRegex = (getRegexes() || []).find(r => r.id === CONFIG.HIDE_ID);
        if (!hideRegex) return true;
        return hideRegex.markdownOnly === false;
    }

    function setThoughtVisible(visible) {
        updateMemory(regexes => {
            const r = regexes.find(r => r.id === CONFIG.HIDE_ID);
            if (r) {
                r.disabled = false;
                r.markdownOnly = !visible;
            }
        });
    }

    function setBeautyStyle(style, expanded) {
        const targetId = getStyleId(style, expanded);
        updateMemory(regexes => {
            for (const id of ALL_STYLE_IDS) {
                const r = regexes.find(r => r.id === id);
                if (r) r.disabled = (id !== targetId);
            }
        });
    }

    function disableAllBeauty() {
        updateMemory(regexes => {
            for (const id of ALL_STYLE_IDS) {
                const r = regexes.find(r => r.id === id);
                if (r) r.disabled = true;
            }
        });
    }

    function getCurrentLastMessageId() {
        try { return getLastMessageId?.() ?? -1; } catch { return -1; }
    }

    async function forceRefresh(messageId) {
        const id = messageId ?? getCurrentLastMessageId();
        if (id < 0) return;
        await setChatMessages([{ message_id: id }], { refresh: 'affected' });
    }

    function getCurrentStyleName() {
        const names = { HUSHE: '狐神抚', JIANYUE: '简约黑', BIAOLI: '表裏1.0' };
        const base = names[state.currentStyle] || '未知样式';
        return base + (state.isExpanded ? '（展开）' : '（收起）');
    }

    function isStreamingEnabled() {
        try {
            const preset = getPreset?.('in_use');
            return preset?.settings?.should_stream === true;
        } catch { return false; }
    }

    async function setStreaming(enabled) {
        await updatePresetWith('in_use', (preset) => {
            preset.settings.should_stream = enabled;
            return preset;
        });
    }

    // ==================== 事件处理 ====================

    function onGenStart(type, option, dryRun) {
        if (dryRun || !state.enabled) return;

        // 🔧 兼容搜索引擎插件：搜索引擎分析时跳过
        if (window.__searchEngineBusy) {
            log('⏭️ 检测到搜索引擎正在分析，跳过本次生成事件');
            return;
        }

        log('⚡ 生成开始');

        state.isGenerating = true;

        // 用户已隐藏思维链 → 不干预
        if (!isThoughtVisible()) {
            log('思维链已被用户隐藏，跳过');
            return;
        }

        // 临时隐藏：禁用美化 + 隐藏思维链
        disableAllBeauty();
        setThoughtVisible(false);
        log('已临时隐藏思维链');

        setTimeout(async () => {
            await forceRefresh(getCurrentLastMessageId());
        }, CONFIG.HIDE_DELAY);
    }

    function onGenEnd() {
        if (!state.enabled) return;

        // 🔧 兼容搜索引擎插件：搜索引擎分析时跳过
        if (window.__searchEngineBusy) {
            log('⏭️ 检测到搜索引擎正在分析，跳过本次生成结束事件');
            return;
        }

        log('✅ 生成结束');

        state.isGenerating = false;

        setTimeout(async () => {
            // 恢复用户偏好的样式
            setBeautyStyle(state.currentStyle, state.isExpanded);
            // 恢复思维链可见（生成前是可见的才会走到这里）
            setThoughtVisible(true);
            log('已恢复思维链显示');

            await forceRefresh(getCurrentLastMessageId());
            log('刷新完成');
        }, CONFIG.RESTORE_DELAY);
    }

    // ==================== 事件绑定/解绑 ====================

    function bindEvents() {
        unbindEvents();
        const h1 = eventOn?.(tavern_events.GENERATION_STARTED, onGenStart);
        const h2 = eventOn?.(tavern_events.GENERATION_ENDED, onGenEnd);
        if (h1) state.eventHandles.push(h1);
        if (h2) state.eventHandles.push(h2);
        log('事件已绑定');
    }

    function unbindEvents() {
        state.eventHandles.forEach(h => h?.stop?.());
        state.eventHandles = [];
        log('事件已解绑');
    }

    // ==================== 初始化 ====================

    function initialize() {
        log('🚀 开始初始化');

        const savedEnabled = localStorage.getItem(CONFIG.ENABLED_KEY);

        setTimeout(async () => {
            setBeautyStyle(state.currentStyle, state.isExpanded);
            const lastId = getCurrentLastMessageId();
            if (lastId >= 0) await forceRefresh(lastId);

            if (savedEnabled === 'true' || isStreamingEnabled()) {
                state.enabled = true;
                localStorage.setItem(CONFIG.ENABLED_KEY, 'true');
                bindEvents();

                if (!isStreamingEnabled()) {
                    await setStreaming(true);
                }

                toastr?.success('🌊 平滑思维链已开启');
                log('✅ 自动启用平滑流式');
            } else {
                log('流式传输未开启，待用户手动开启');
            }

            log('🎉 初始化完成 | 样式:', getCurrentStyleName(),
                '| 思维链:', isThoughtVisible() ? '可见' : '隐藏',
                '| 平滑流式:', state.enabled ? '开' : '关',
                '| 搜索引擎兼容:', '已启用');
        }, CONFIG.INIT_DELAY);
    }

    // ==================== 按钮逻辑 ====================

    // 🌊 平滑流式开关
    eventOn?.(getButtonEvent('🌊 平滑流式'), async () => {
        state.enabled = !state.enabled;
        localStorage.setItem(CONFIG.ENABLED_KEY, state.enabled.toString());

        if (state.enabled) {
            bindEvents();
            if (!isStreamingEnabled()) {
                await setStreaming(true);
                toastr?.success('🌊 平滑流式：已开启（流式传输已自动打开）');
            } else {
                toastr?.success('🌊 平滑流式：已开启');
            }
        } else {
            unbindEvents();
            state.isGenerating = false;
            toastr?.info('🌊 平滑流式：已关闭');
        }
    });

    // 🔍 思维链可见性切换
    eventOn?.(getButtonEvent('🔍 思维链可见'), async () => {
        const nowVisible = isThoughtVisible();
        setThoughtVisible(!nowVisible);
        await forceRefresh(getCurrentLastMessageId());
        toastr?.success('🔍 思维链：' + (!nowVisible ? '可见' : '隐藏'));
    });

    // 🔄 思维链样式切换（只在狐神抚 ↔ 简约黑 ↔ 表裏1.0 之间切换，保留展开/收起状态）
    eventOn?.(getButtonEvent('🔁 思维链样式'), async () => {
        const order = ['HUSHE', 'JIANYUE', 'BIAOLI'];
        const idx = order.indexOf(state.currentStyle);
        state.currentStyle = order[(idx + 1) % order.length];
        localStorage.setItem(CONFIG.STYLE_KEY, state.currentStyle);
        setBeautyStyle(state.currentStyle, state.isExpanded);
        await forceRefresh(getCurrentLastMessageId());
        toastr?.success('🔄 样式：' + getCurrentStyleName());
    });

    // 📖 默认展开/收起切换（保持当前样式不变）
    eventOn?.(getButtonEvent('📖 展开🔀'), async () => {
        state.isExpanded = !state.isExpanded;
        localStorage.setItem(CONFIG.EXPAND_KEY, state.isExpanded.toString());
        setBeautyStyle(state.currentStyle, state.isExpanded);
        await forceRefresh(getCurrentLastMessageId());
        toastr?.success('📖 默认：' + (state.isExpanded ? '展开' : '收起'));
    });

    // ==================== 启动 ====================

    if (typeof SillyTavern !== 'undefined') {
        initialize();
    } else {
        const check = setInterval(() => {
            if (typeof SillyTavern !== 'undefined') {
                clearInterval(check);
                initialize();
            }
        }, 500);
    }

    log('📦 脚本已加载（兼容搜索引擎插件）');
})();

