    function escapeHtml(value) {
        return String(value ?? '')
            .replaceAll('&', '&amp;')
            .replaceAll('<', '&lt;')
            .replaceAll('>', '&gt;')
            .replaceAll('"', '&quot;')
            .replaceAll("'", '&#039;');
    }

    function escapeJsonStringContent(value) {
        return JSON.stringify(String(value ?? '')).slice(1, -1);
    }

    function hasQueryParam(url, name) {
        try {
            const parsed = new URL(url, location.href);
            return parsed.searchParams.has(name);
        } catch {
            return new RegExp(`[?&]${name.replace(/[.*+?^${}()|[\]\\]/g, '\\$&')}=`, 'i').test(url);
        }
    }

    function appendQueryParam(url, name, value) {
        if (!name || value == null || value === '') return url;
        const sep = url.includes('?') ? '&' : '?';
        return `${url}${sep}${encodeURIComponent(name)}=${encodeURIComponent(value)}`;
    }

    function clampNumber(value, min, max, fallback) {
        const n = Number(value);
        if (!Number.isFinite(n)) return fallback;
        return Math.min(max, Math.max(min, n));
