    async function searchCustomApi(keyword, signal) {
        const settings = loadSettings();
        const url = settings.searchApiUrl?.trim();
        if (!url) return null;

        const method = (settings.searchApiMethod || 'GET').toUpperCase();
        const key = settings.searchApiKey?.trim() || '';
        const language = settings.searchApiLanguage?.trim() || 'zh-CN';
        const shouldUseLanguage = language && language !== 'auto';

        const headers = { 'Accept': 'application/json' };
        if (key && settings.searchApiKeyHeaderName?.trim()) {
            const template = settings.searchApiKeyHeaderTemplate?.trim() || '{key}';
            headers[settings.searchApiKeyHeaderName.trim()] = template.replaceAll('{key}', key);
        }

        try {
            let finalUrl = url
                .replaceAll('{keyword}', encodeURIComponent(keyword))
                .replaceAll('{language}', encodeURIComponent(language));
            let body = null;

            if (method === 'POST') {
                if (!headers['Content-Type']) headers['Content-Type'] = 'application/json';
                const template = settings.searchApiBodyTemplate?.trim() || '{"query":"{keyword}"}';
                body = template
                    .replaceAll('{keyword}', escapeJsonStringContent(keyword))
                    .replaceAll('{language}', escapeJsonStringContent(language));
            } else {
                if (key && settings.searchApiQueryParam?.trim()) {
                    finalUrl = appendQueryParam(finalUrl, settings.searchApiQueryParam.trim(), key);
                }
                if (settings.searchApiExtraParams?.trim()) {
                    const extra = settings.searchApiExtraParams.trim()
                        .replaceAll('{keyword}', encodeURIComponent(keyword))
                        .replaceAll('{language}', encodeURIComponent(language));
                    finalUrl += (extra.startsWith('&') || extra.startsWith('?') ? '' : (finalUrl.includes('?') ? '&' : '?')) + extra;
                }
                if (shouldUseLanguage && !hasQueryParam(finalUrl, 'language') && !hasQueryParam(finalUrl, 'lang')) {
                    finalUrl = appendQueryParam(finalUrl, 'language', language);
                }
            }

            log(`自定义搜索: ${method} ${finalUrl}`);
            const fetchOpts = { method, headers, signal };
            if (body) fetchOpts.body = body;

            const resp = await fetch(finalUrl, fetchOpts);
            if (!resp.ok) { warn(`自定义搜索 HTTP ${resp.status}`); return null; }

            const data = await resp.json();
            return extractSearchResults(data, keyword, settings);
        } catch (e) {
            if (e.name !== 'AbortError') warn(`自定义搜索失败: ${keyword}`, e.message);
            return null;
        }
    }

    function extractSearchResults(data, keyword, settings) {
        const path = settings.searchApiResultPath?.trim() || 'results';
        let list = getByPath(data, path);
        if (!Array.isArray(list)) {
            const alternatives = ['results', 'items', 'data', 'response.results', 'organic', 'webPages.value'];
            for (const alt of alternatives) {
                list = getByPath(data, alt);
                if (Array.isArray(list)) break;
            }
        }
        if (!Array.isArray(list) || !list.length) {
            warn('搜索结果列表为空，路径:', path);
            return null;
        }

        const titleField = settings.searchApiTitleField?.trim() || 'title';
        const snippetField = settings.searchApiSnippetField?.trim() || 'content';
        const linkField = settings.searchApiLinkField?.trim() || 'url';
        const limit = settings.searchResultsCount || CONFIG.searchResultsCount;
        const maxLen = settings.maxExtractLength || CONFIG.maxExtractLength;

        const results = [];
        for (let i = 0; i < Math.min(list.length, limit * 2); i++) {
            const item = list[i];
            const title = getByPath(item, titleField) || '';
            const snippet = getByPath(item, snippetField) || '';
            const link = getByPath(item, linkField) || '';

            if (!snippet && !title) continue;

            let text = '';
            if (title) text += `【${title}】`;
            if (snippet) {
                const clean = String(snippet).replace(/<[^>]+>/g, '').replace(/\n+/g, ' ').replace(/\s+/g, ' ').slice(0, maxLen).trim();
                text += clean;
            }
            if (link) text += `\n🔗 ${link}`;

            if (text && isRelevant(keyword, text)) {
                results.push(text);
                if (results.length >= limit) break;
            }
        }

        return results.length ? results.join('\n') : null;
    }

    function getByPath(obj, path) {
        if (!obj || !path) return obj;
        const keys = path.split('.');
        let current = obj;
        for (const key of keys) {
            if (current == null) return undefined;
            if (/^\d+$/.test(key)) {
                current = current[parseInt(key)];
            } else {
                current = current[key];
            }
        }
        return current;
    }

    function isRelevant(keyword, text) {
        const kwLower = keyword.toLowerCase();
        const textLower = text.toLowerCase();
        if (textLower.includes(kwLower)) return true;
        const kwChars = [...keyword].filter(c => c.trim() && !/[a-zA-Z0-9]/.test(c));
        if (kwChars.length >= 2) return kwChars.filter(c => text.includes(c)).length >= kwChars.length * 0.5;
        const kwWords = kwLower.split(/\s+/).filter(w => w.length > 1);
        if (kwWords.length >= 2) return kwWords.filter(w => textLower.includes(w)).length >= kwWords.length * 0.5;
        return false;
    }

    async function searchWikipedia(keyword, signal) {
        try {
            const settings = loadSettings();
            const limit = settings.searchResultsCount || CONFIG.searchResultsCount;
            const maxLen = settings.maxExtractLength || CONFIG.maxExtractLength;
            let searchTerm = keyword;
            try {
                const suggestUrl = `https://zh.wikipedia.org/w/api.php?action=opensearch&search=${encodeURIComponent(keyword)}&limit=1&format=json&origin=*`;
                const suggestResp = await fetch(suggestUrl, { signal });
                if (suggestResp.ok) {
                    const suggestData = await suggestResp.json();
                    if (Array.isArray(suggestData[1]) && suggestData[1].length > 0 && suggestData[1][0] !== keyword) {
                        searchTerm = suggestData[1][0];
                    }
                }
            } catch {}
            const searchUrl = `https://zh.wikipedia.org/w/api.php?action=query&list=search&srsearch=${encodeURIComponent(searchTerm)}&format=json&origin=*&srlimit=${limit}`;
            const searchResp = await fetch(searchUrl, { signal });
            if (!searchResp.ok) return null;
            const searchData = await searchResp.json();
            const pages = searchData?.query?.search;
            if (!pages?.length) return null;
            const pageIds = pages.map(p => p.pageid);
            const extractsUrl = `https://zh.wikipedia.org/w/api.php?action=query&prop=extracts&exintro&explaintext&pageids=${pageIds.join('|')}&format=json&origin=*`;
            const extractResp = await fetch(extractsUrl, { signal });
            if (!extractResp.ok) return null;
            const extractData = await extractResp.json();
            const extracts = [];
            for (const pid of pageIds) {
                const page = extractData?.query?.pages?.[pid];
                if (page?.extract) {
                    const clean = page.extract.replace(/\n+/g, ' ').replace(/\s+/g, ' ').slice(0, maxLen).trim();
                    if (clean && isRelevant(keyword, page.title + ' ' + clean)) extracts.push(`【${page.title}】${clean}`);
                }
            }
            return extracts.length > 0 ? extracts.join('\n') : null;
        } catch (e) {
            if (e.name !== 'AbortError') warn(`Wiki 失败: ${keyword}`, e.message);
            return null;
        }
    }

    async function searchMoegirl(keyword, signal) {
        try {
            const settings = loadSettings();
            const limit = settings.searchResultsCount || CONFIG.searchResultsCount;
            const maxLen = settings.maxExtractLength || CONFIG.maxExtractLength;
            const url = `https://zh.moegirl.org.cn/api.php?action=query&list=search&srsearch=${encodeURIComponent(keyword)}&format=json&origin=*&srlimit=${limit}`;
            const resp = await fetch(url, { signal });
            if (!resp.ok) return null;
            const data = await resp.json();
            const pages = data?.query?.search;
            if (!pages?.length) return null;
            const results = pages
                .filter(p => isRelevant(keyword, `${p.title} ${p.snippet || ''}`))
                .map(p => {
                    const snippet = String(p.snippet || '').replace(/<[^>]+>/g, '').replace(/\s+/g, ' ').slice(0, maxLen).trim();
                    return `【萌娘百科：${p.title}】${snippet}`;
                }).filter(Boolean);
            return results.length ? results.join('\n') : null;
        } catch (e) {
            if (e.name !== 'AbortError') warn(`萌百失败: ${keyword}`, e.message);
            return null;
        }
    }

    async function searchAllKeywords(keywords) {
        const settings = loadSettings();
        const controller = new AbortController();
        const timeoutId = setTimeout(() => controller.abort(), settings.searchTimeout || CONFIG.searchTimeout);
        try {
            const tasks = [];
            for (const kw of keywords) {
                if (settings.enableWikipedia) tasks.push({ kw, source: 'wiki', promise: searchWikipedia(kw, controller.signal) });
                if (settings.enableMoegirl) tasks.push({ kw, source: 'moegirl', promise: searchMoegirl(kw, controller.signal) });
                if (settings.enableCustomSearch) tasks.push({ kw, source: 'custom', promise: searchCustomApi(kw, controller.signal) });
            }
            const results = await Promise.allSettled(tasks.map(t => t.promise));
            const searchResults = new Map();
            for (let i = 0; i < tasks.length; i++) {
                const res = results[i];
                if (res.status === 'fulfilled' && res.value) {
                    const old = searchResults.get(tasks[i].kw) || '';
                    searchResults.set(tasks[i].kw, old ? `${old}\n${res.value}` : res.value);
                }
            }
            return searchResults;
        } finally { clearTimeout(timeoutId); }
    }

    function getFullContext(currentMessageId) {
        const parts = [];
        try {
            const context = ST()?.getContext?.();
            const character = context?.characters?.[context?.characterId];
            if (character) {
                parts.push(`【角色名】${character.name || '(未知)'}`);
                if (character.description?.trim()) parts.push(`【角色描述】${character.description}`);
                if (character.personality?.trim()) parts.push(`【性格】${character.personality}`);
                if (character.scenario?.trim()) parts.push(`【场景】${character.scenario}`);
            }
            const persona = context?.personas?.[context?.personaId];
            if (persona?.description?.trim()) parts.push(`【用户人设】${persona.description}`);
        } catch (e) {}
        try {
            const getLastMessageId = getFn('getLastMessageId');
            const getChatMessages = getFn('getChatMessages');
            if (typeof getLastMessageId === 'function' && typeof getChatMessages === 'function') {
                const lastId = currentMessageId ?? getLastMessageId();
                const startId = Math.max(0, lastId - 15);
                const messages = getChatMessages(`${startId}-${lastId}`);
                parts.push(`【聊天记录】\n${messages.filter(m => !m.is_hidden).map(m => {
                    const who = m.role === 'user' ? '用户' : (m.name || m.role);
                    return `[${who}] ${(m.message || '').slice(0, 300)}`;
                }).join('\n')}`);
            }
        } catch (e) {}
        return parts.join('\n\n');
    }

    async function callCustomAnalysisApi({ system, user }, settings) {
        const apiurl = normalizeBaseURL(settings.customApiUrl);
        const model = String(settings.customModel || '').trim();

        if (!apiurl) throw new Error('自定义分析 API 地址为空');
        if (!model) throw new Error('自定义分析模型为空，请选择模型后保存设置');

        const headers = {
            'Content-Type': 'application/json',
            'Accept': 'application/json',
        };

        if (settings.customApiKey) {
            headers.Authorization = `Bearer ${settings.customApiKey}`;
        }

        const body = {
            model,
            messages: [
                { role: 'system', content: system },
                { role: 'user', content: user },
            ],
            stream: false,
            max_tokens: Math.max(1, Number(settings.customMaxTokens || 4096)),
            temperature: clampNumber(settings.customTemperature, 0, 2, 1),
            frequency_penalty: clampNumber(settings.customFrequencyPenalty, -2, 2, 0),
            presence_penalty: clampNumber(settings.customPresencePenalty, -2, 2, 0),
            top_p: clampNumber(settings.customTopP, 0, 1, 1),
        };

        if (Number(settings.customTopK) > 0) {
            body.top_k = clampNumber(settings.customTopK, 0, 500, 0);
        }

        const resp = await fetch(`${apiurl}/chat/completions`, {
            method: 'POST',
            headers,
            body: JSON.stringify(body),
        });

        const text = await resp.text();

        if (!resp.ok) {
            throw new Error(`自定义分析 API 请求失败：HTTP ${resp.status} ${text.slice(0, 300)}`);
        }

        let json;
        try {
            json = JSON.parse(text);
        } catch {
            throw new Error(`自定义分析 API 返回非 JSON：${text.slice(0, 300)}`);
        }

        const content = json?.choices?.[0]?.message?.content
            || json?.choices?.[0]?.text
            || json?.content
            || '';

        if (!content) {
            throw new Error('自定义分析 API 返回内容为空');
        }

        return content;
    }

    async function husouGenerateTask({ system, user }) {
        const settings = loadSettings();

        if (settings.analysisApi === 'custom') {
            return await callCustomAnalysisApi({ system, user }, settings);
        }

        const win = getSTWindow();
        const generate = win.generate || window.generate;
        const generateRaw = win.generateRaw || window.generateRaw;

        const common = {
            user_input: user,
            should_silence: true,
            should_stream: false,
            max_chat_history: 0,
        };

        if (settings.searchPresetMode === 'builtin' || settings.searchPresetMode === 'current') {
            if (typeof generateRaw !== 'function') throw new Error('无 generateRaw');
            const result = await generateRaw({
                ...common,
                ordered_prompts: [
                    { role: 'system', content: system },
                    'user_input',
                ],
            });
            return typeof result === 'string' ? result : result?.content || '';
        }

        if (settings.searchPresetMode === 'other' && settings.searchPresetName) {
            if (typeof generate !== 'function') throw new Error('无 generate');
            const result = await generate({
                ...common,
                preset_name: settings.searchPresetName,
                overrides: {
                    char_description: '',
                    char_personality: '',
                    scenario: '',
                    world_info_before: '',
                    world_info_after: '',
                    persona_description: '',
                    dialogue_examples: '',
                    chat_history: { prompts: [] },
                },
                injects: [
                    {
                        role: 'system',
                        content: system,
                        position: 'in_chat',
                        depth: 0,
                        should_scan: false,
                    },
                ],
            });
            return typeof result === 'string' ? result : result?.content || '';
        }

        throw new Error('未知搜索预设模式');
    }

    async function analyzeContext(contextText) {
        if (!contextText || contextText.length < 20) return [];
        const settings = loadSettings();
        const maxKw = settings.maxKeywords || CONFIG.maxKeywords;

        let existingInjection = '';
        if (settings.smartSkip) {
            try {
                existingInjection = getCurrentInjectionFromChar();
                if (existingInjection.length > 3000) existingInjection = existingInjection.slice(0, 3000) + '...(已截断)';
            } catch (e) {}
        }

        const system = `你是专有名词提取助手。请仔细阅读以下上下文，理解当前对话中涉及的角色、作品、世界观。上下文：${contextText}`;
        const user = `以下是你之前已经搜索并注入过的内容：\n${settings.smartSkip ? (existingInjection || '（暂无已搜索内容）') : '（智能跳过已关闭）'}\n\n请根据上下文${settings.smartSkip ? '和已有搜索内容' : ''}，提取还需要搜索的专有名词。\n\n⚠️核心规则：按递进层级提取关键词。先提取作品名本身，再提取"作品名+角色名/物品名/组织名"，最后提取"作品名+角色名+子项目"。\n\n规则：\n1. 如果上下文有作品名（如"原神"），第一个关键词必须是作品名本身，不要跳过作品名\n2. 然后提取"作品名+角色名"（如"原神 可莉"、"原神 琴"）\n3. 如果角色有特定技能、装备、称号，再提取"作品名+角色名+项目"（如"原神 可莉 蹦蹦炸弹"、"原神 西风骑士团"）\n4. 禁止单独搜一个没有作品前缀的普通名词（如"琴"、"骑士团"）\n5. 层级关系：先宽后窄，先搜大的再搜小的\n6. ${settings.smartSkip ? '如果已有搜索内容中已经出现了某个名词，且上下文没有提到该名词的新的、不同的信息需求，直接跳过不要重复提取。同一个角色/作品只提取一次，不要因为已有内容写得不完整就反复提取' : '智能跳过已关闭，不要跳过任何名词'}\n7. 忽略日常词汇\n8. 最多 ${maxKw} 个\n\n返回纯 JSON 数组，示例：["原神", "原神 可莉", "原神 琴", "原神 阿贝多", "原神 嘟嘟可", "原神 西风骑士团", "原神 可莉 蹦蹦炸弹"]。没有就返回 []。`;
        try {
            const text = await husouGenerateTask({ system, user });
            const match = text.match(/\[[\s\S]*?\]/);
            if (!match) return [];
            const arr = JSON.parse(match[0]);
            const keywords = Array.isArray(arr) ? arr.filter(k => typeof k === 'string' && k.trim()).map(k => k.trim()).slice(0, maxKw) : [];
            updateKeywordPanel(keywords);
            return keywords;
        } catch (e) { return []; }
    }

    async function fetchPageWithJina(url, signal) {
