    async function filterSearchResults(searchResults) {
        const settings = loadSettings();
        if (!searchResults.size) return new Map();
        let enrichedResults = new Map(searchResults);
        if (settings.enableJinaFetch && settings.aiFilter) {
            const jinaController = new AbortController();
            const jinaTimeout = setTimeout(() => jinaController.abort(), settings.searchTimeout || CONFIG.searchTimeout);
            try {
                for (const [kw, text] of searchResults) {
                    const urls = [...text.matchAll(/🔗 (https?:\/\/\S+)/g)].map(m => m[1]).slice(0, 2);
                    const fetchedTexts = [];
                    for (const url of urls) {
                        const content = await fetchPageWithJina(url, jinaController.signal);
                        if (content) {
                            const clean = content.replace(/\n{3,}/g, '\n\n').trim();
                            fetchedTexts.push(`--- 来自 ${url} ---\n${clean}`);
                        }
                    }
                    if (fetchedTexts.length) {
                        enrichedResults.set(kw, text + '\n\n【网页全文】\n' + fetchedTexts.join('\n\n'));
                    }
                }
            } catch (e) {
                warn('Jina 抓取阶段出错:', e.message);
            } finally {
                clearTimeout(jinaTimeout);
            }
        }
        if (!settings.aiFilter) {
            return searchResults;
        }

        // 获取已有的搜索注入内容
        let existingKnowledge = '';
        try {
            existingKnowledge = getCurrentInjectionFromChar();
            if (existingKnowledge.length > 5000) existingKnowledge = existingKnowledge.slice(0, 5000) + '...(已截断)';
        } catch (e) {}

        let raw = '';
        for (const [k, v] of enrichedResults) {
            raw += `\n=== 「${k}」===\n${v}\n`;
        }
        const system = `你是信息整理助手。以下是本次新搜索到的原始结果，以及之前已经整理过的知识。请对比两者，只从新结果中提取之前没有的内容，补充到已有知识中。

【本次新搜索的原始结果】
${raw}

【之前已整理的知识】
${existingKnowledge || '（暂无）'}

严格规则：
1. 与上下文中的角色、世界观、设定完全无关的内容直接丢弃
2. 如果某个信息在"之前已整理的知识"中已经存在（哪怕只是一部分），不要再重复输出相同的内容。只输出之前完全没有出现过的新信息
3. 只输出本次新搜索中发现的、之前没有的新内容
4. 如果没有任何新内容，严格输出（无可用信息）
5. 多条来源合并去重，用自己的话概括
6. 每条说明不超过4000字
7. 不要解释判断过程`;
        const user = `请对比新旧内容，只输出本次新增的信息。
只允许输出以下两种格式之一：
如果有新信息，输出：
【过滤后的知识库】
【关于「名称」的说明】
新增的核心信息...
如果没有任何新信息，必须严格输出：
【过滤后的知识库】
（无可用信息）
不要解释，不要输出旧内容。`;
        try {
            const text = await husouGenerateTask({ system, user });
            const normalized = String(text || '').trim();
            const match = normalized.match(/【过滤后的知识库】([\s\S]*?)(?:$|---)/);
            if (!match) {
                warn('AI过滤结果未按格式返回，已丢弃本次搜索结果:', normalized.slice(0, 300));
                return new Map();
            }
            const content = match[1].trim();
            if (!content || /（?\s*无可用信息\s*）?/i.test(content)) {
                log('AI过滤判定：无新信息，已丢弃搜索结果');
                return new Map();
            }
            const map = new Map();
            const sections = content.split(/【关于「(.+?)」的说明】/);
            for (let i = 1; i < sections.length; i += 2) {
                const name = sections[i]?.trim();
                const body = sections[i + 1]?.trim();
                if (!name || !body) continue;
                if (/无可用信息|无相关信息|全部无关|完全无关|discard|irrelevant/i.test(body)) continue;
                map.set(name, body);
            }
            if (!map.size) {
                warn('AI过滤结果没有可解析条目，已丢弃本次搜索结果:', normalized.slice(0, 300));
                return new Map();
            }
            return map;
        } catch (e) {
            warn('AI过滤失败，已丢弃本次搜索结果:', e.message);
            return new Map();
        }
    }

    function getCurrentInjectionFromChar() {
        try {
            const char = ST()?.getContext?.()?.characters?.[ST().getContext?.()?.characterId];
            if (!char) return '';
            const p = char.personality || '';
            const start = '【🦊狐搜外部搜索参考';
            const end = '【外部搜索参考结束】';

            // 收集所有匹配块
            const blocks = [];
            let searchFrom = 0;
            while (true) {
                const s = p.indexOf(start, searchFrom);
                if (s === -1) break;
                const e = p.indexOf(end, s);
                if (e === -1) break;
                blocks.push(p.slice(s, e + end.length));
                searchFrom = e + end.length;
            }

            // 也收集旧版标记
            const oldStart = '【🔍 外部搜索参考';
            searchFrom = 0;
            while (true) {
                const s = p.indexOf(oldStart, searchFrom);
                if (s === -1) break;
                const e = p.indexOf(end, s);
                if (e === -1) break;
                blocks.push(p.slice(s, e + end.length));
                searchFrom = e + end.length;
            }

            return blocks.join('\n');
        } catch { return ''; }
    }

    async function saveToCharPersonality(filteredResults) {
        const settings = loadSettings();
        if (!settings.saveToPersonality || !filteredResults?.size) return;
        const timestamp = new Date().toISOString().split('T')[0];
        try {
            const ctx = ST()?.getContext?.();
            const char = ctx?.characters?.[ctx?.characterId];
            if (!char) return;
            const entries = [...filteredResults].map(([n, c]) => `【关于「${n}」的说明】\n${c}`);
            const block = `\n\n【🦊狐搜外部搜索参考 - ${timestamp}】\n${entries.join('\n\n')}\n【外部搜索参考结束】`;
            let newP = char.personality || '';
            newP = (newP ? newP + '\n' : '') + block;
            char.personality = newP;
            const ee = getFn('eventEmit');
            if (ee) await ee(getSTWindow().tavern_events?.CHARACTER_EDITED, { detail: { id: ctx.characterId, character: char } });
            log('已保存到角色性格（追加模式）');
        } catch (e) { warn('保存失败', e); }
    }

    async function clearSearchInjection() {
        try {
            const ctx = ST()?.getContext?.();
            const char = ctx?.characters?.[ctx?.characterId];
            if (!char) { toast('无角色卡', 'error'); return; }
            let cleaned = char.personality || '';
            const esc = s => s.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
            cleaned = cleaned.replace(new RegExp(`\\n*${esc('【🦊狐搜外部搜索参考')}[\\s\\S]*?${esc('【外部搜索参考结束】')}\\n*`, 'g'), '');
            cleaned = cleaned.replace(new RegExp(`\\n*${esc('【🔍 外部搜索参考')}[\\s\\S]*?${esc('【外部搜索参考结束】')}\\n*`, 'g'), '');
            if (cleaned.trim() === (char.personality||'').trim()) { toast('🧹 无搜索注入', 'info'); return; }
            char.personality = cleaned.trim();
            const ee = getFn('eventEmit');
            if (ee) await ee(getSTWindow().tavern_events?.CHARACTER_EDITED, { detail: { id: ctx.characterId, character: char } });
            pendingInject = null;
            toast('🧹 已清除', 'success');
            refreshInjectionManager();
        } catch (e) { toast('清除失败', 'error'); }
    }

    async function injectCustomContent(text) {
        if (!text?.trim()) { toast('内容为空', 'warning'); return; }
        const timestamp = new Date().toISOString().split('T')[0];
        const block = `\n\n【🦊狐搜外部搜索参考 - ${timestamp} 手动编辑】\n${text.trim()}\n【外部搜索参考结束】`;
        try {
            const ctx = ST()?.getContext?.();
            const char = ctx?.characters?.[ctx?.characterId];
            if (!char) { toast('无角色卡', 'error'); return; }
            let newP = char.personality || '';
            if (newP.includes('【🦊狐搜外部搜索参考')) newP = newP.split('【🦊狐搜外部搜索参考')[0].trim() + block;
            else if (newP.includes('【🔍 外部搜索参考')) newP = newP.split('【🔍 外部搜索参考')[0].trim() + block;
            else newP = (newP ? newP + '\n' : '') + block;
            char.personality = newP;
            const ee = getFn('eventEmit');
            if (ee) await ee(getSTWindow().tavern_events?.CHARACTER_EDITED, { detail: { id: ctx.characterId, character: char } });
            pendingInject = new Map([['手动注入', text.trim()]]);
            toast('✅ 已注入', 'success');
            refreshInjectionManager();
        } catch (e) { toast('注入失败', 'error'); }
    }

