    function buildInjectBlock(map) {
        if (!map?.size) return '';
        const secs = [...map].map(([n, c]) => `【关于「${n}」的说明】\n${c}`);
        return `\n\n【🦊狐搜外部搜索参考 - 以下信息来自网络，可能不完全准确】\n${secs.join('\n\n')}\n【外部搜索参考结束】\n`;
    }

    function injectIntoPromptArray(arr) {
        if (!loadSettings().injectCurrentPrompt || !pendingInject?.size || !Array.isArray(arr)) return;
        const block = buildInjectBlock(pendingInject);
        if (!block) return;
        arr.unshift({ role: 'system', content: block });
        pendingInject = null;
        log('已注入（已清空缓存）');
    }

    async function runSearchFlow(messageId) {
        const s = loadSettings();
        if (!s.enableAutoSearch || isRunningSearch) return;
        if (lastHandledMessageId === messageId) return;

        const getChatMessages = getFn('getChatMessages');
        if (typeof getChatMessages !== 'function') return;

        const msg = getChatMessages(messageId)?.[0];
        if (!msg || !msg.message?.trim()) {
            toast('狐搜：无法读取该楼层消息', 'warning');
            return;
        }

        lastHandledMessageId = messageId;
        isRunningSearch = true;
        pendingInject = null;
        let completed = false;

        try {
            log(`消息 #${messageId}:`, msg.message.slice(0, 120));
            toast('狐搜分析中…', 'info');
            const ctx = getFullContext(messageId);
            const keywords = await analyzeContext(ctx);
            if (!keywords.length) { toast('狐搜：无关键词', 'info'); completed = true; return; }
            const raw = await searchAllKeywords(keywords);
            if (!raw.size) { toast('狐搜：搜索无结果', 'warning'); completed = true; return; }
            log(`原始结果 ${raw.size} 个`);
            const filtered = await filterSearchResults(raw);
            if (!filtered?.size) { toast('狐搜：过滤无结果', 'warning'); completed = true; return; }
            pendingInject = filtered;
            await saveToCharPersonality(filtered);
            refreshInjectionManager();
            toast(`狐搜完成：${filtered.size} 条`, 'success');
            completed = true;
        } catch (e) {
            pendingInject = null;
            lastHandledMessageId = null;
            toast(`失败：${e.message}`, 'error');
        } finally {
            if (!completed) lastHandledMessageId = null;
            isRunningSearch = false;
        }
    }

    async function manualSearchFlow(messageId) {
        if (isRunningSearch) { toast('搜索进行中，请稍候', 'warning'); return; }
        const getChatMessages = getFn('getChatMessages');
        if (typeof getChatMessages !== 'function') return;
        const msg = getChatMessages(messageId)?.[0];
        if (!msg || !msg.message?.trim()) {
            toast('无法读取该楼层消息', 'warning');
            return;
        }
        lastHandledMessageId = null;
        isRunningSearch = true;
        pendingInject = null;
        try {
            log(`手动搜索 #${messageId}:`, msg.message.slice(0, 120));
            toast('狐搜手动搜索中…', 'info');
            const ctx = getFullContext(messageId);
            const keywords = await analyzeContext(ctx);
            if (!keywords.length) { toast('狐搜：无关键词', 'info'); return; }
            const raw = await searchAllKeywords(keywords);
            if (!raw.size) { toast('狐搜：搜索无结果', 'warning'); return; }
            log(`原始结果 ${raw.size} 个`);
            const filtered = await filterSearchResults(raw);
            if (!filtered?.size) { toast('狐搜：过滤无结果', 'warning'); return; }
            pendingInject = filtered;
            await saveToCharPersonality(filtered);
            refreshInjectionManager();
            toast(`手动搜索完成：${filtered.size} 条`, 'success');
        } catch (e) { pendingInject = null; toast(`失败：${e.message}`, 'error'); }
        finally { isRunningSearch = false; }
    }

    function registerSearchListeners() {
        const win = getSTWindow();
        const eo = win.eventOn || window.eventOn;
        const emf = win.eventMakeFirst || window.eventMakeFirst;
        const te = win.tavern_events || window.tavern_events;
        if (!eo || !te) return;
        registeredListeners.forEach(l => l.stop());
        registeredListeners = [];
        registeredListeners.push(eo(te.MESSAGE_SENT, async id => runSearchFlow(id)));
        if (te.CHAT_COMPLETION_PROMPT_READY) registeredListeners.push(eo(te.CHAT_COMPLETION_PROMPT_READY, d => { if (!d?.dryRun && Array.isArray(d?.chat)) injectIntoPromptArray(d.chat); }));
        if (te.GENERATE_AFTER_DATA) {
            const fn = (d, dry) => { if (!dry && Array.isArray(d?.prompt)) injectIntoPromptArray(d.prompt); };
            if (emf) { emf(te.GENERATE_AFTER_DATA, fn); registeredListeners.push({ stop: () => win.eventRemoveListener?.(te.GENERATE_AFTER_DATA, fn) }); }
            else registeredListeners.push(eo(te.GENERATE_AFTER_DATA, fn));
        }
        if (te.GENERATE_AFTER_COMBINE_PROMPTS) {
            registeredListeners.push(eo(te.GENERATE_AFTER_COMBINE_PROMPTS, r => {
                if (r?.dryRun || !loadSettings().injectCurrentPrompt || !pendingInject?.size) return;
                const block = buildInjectBlock(pendingInject);
                if (!block) return;
                if (Array.isArray(r?.prompt)) r.prompt.unshift({ role: 'system', content: block });
                else if (typeof r?.prompt === 'string') r.prompt = block + '\n' + r.prompt;
                pendingInject = null;
            }));
        }
        if (te.CHAT_CHANGED) registeredListeners.push(eo(te.CHAT_CHANGED, () => { pendingInject = null; lastHandledMessageId = null; isRunningSearch = false; }));
    }

    function registerQuickButtons() {
