    function readSettingsFromPanel(doc) {
        const g = id => doc.getElementById(id);
        return {
            enableAutoSearch: !!g('search_enable_auto')?.checked,
            enableMoegirl: !!g('search_enable_moegirl')?.checked,
            enableWikipedia: !!g('search_enable_wikipedia')?.checked,
            enableCustomSearch: !!g('search_enable_custom')?.checked,
            enableJinaFetch: !!g('search_enable_jina')?.checked,
            smartSkip: !!g('search_smart_skip')?.checked,
            aiFilter: !!g('search_ai_filter')?.checked,
            saveToPersonality: !!g('search_save_personality')?.checked,
            injectCurrentPrompt: !!g('search_inject_prompt')?.checked,
            analysisApi: g('search_analysis_api')?.value || 'current',
            customApiUrl: g('search_custom_api_url')?.value?.trim() || '',
            customApiKey: g('search_custom_api_key')?.value?.trim() || '',
            customModel: g('search_custom_model')?.value?.trim() || '',
            customMaxTokens: Number(g('search_custom_max_tokens')?.value || 4096),
            customTemperature: Number(g('search_custom_temperature')?.value || 1),
            customFrequencyPenalty: Number(g('search_custom_frequency_penalty')?.value || 0),
            customPresencePenalty: Number(g('search_custom_presence_penalty')?.value || 0),
            customTopP: Number(g('search_custom_top_p')?.value || 1),
            customTopK: Number(g('search_custom_top_k')?.value || 0),
            searchPresetMode: g('search_preset_mode')?.value || 'builtin',
            searchPresetName: g('search_preset_name')?.value?.trim() || '',
            searchApiUrl: g('search_api_url')?.value?.trim() || '',
            searchApiMethod: g('search_api_method')?.value || 'GET',
            searchApiKey: g('search_api_key')?.value?.trim() || '',
            searchApiKeyHeaderName: g('search_api_key_header_name')?.value?.trim() || '',
            searchApiKeyHeaderTemplate: g('search_api_key_header_template')?.value?.trim() || '',
            searchApiQueryParam: g('search_api_query_param')?.value?.trim() || '',
            searchApiBodyTemplate: g('search_api_body_template')?.value?.trim() || '',
            searchApiResultPath: g('search_api_result_path')?.value?.trim() || '',
            searchApiTitleField: g('search_api_title_field')?.value?.trim() || '',
            searchApiSnippetField: g('search_api_snippet_field')?.value?.trim() || '',
            searchApiLinkField: g('search_api_link_field')?.value?.trim() || '',
            searchApiLanguage: g('search_api_language')?.value?.trim() || 'zh-CN',
            searchApiExtraParams: g('search_api_extra_params')?.value?.trim() || '',
            maxKeywords: Number(g('search_max_keywords')?.value || CONFIG.maxKeywords),
            searchTimeout: Number(g('search_timeout')?.value || CONFIG.searchTimeout),
            maxExtractLength: Number(g('search_extract_length')?.value || CONFIG.maxExtractLength),
            searchResultsCount: Number(g('search_results_count')?.value || CONFIG.searchResultsCount),
        };
    }

    function bindPanelEvents(doc) {
        const g = id => doc.getElementById(id);
        const enableCustom = g('search_enable_custom');
        const customSection = g('custom_search_api_section');
        if (enableCustom && customSection) {
            enableCustom.addEventListener('change', () => customSection.style.display = enableCustom.checked ? '' : 'none');
        }
        const analysisApi = g('search_analysis_api');
        const customApiSection = g('custom_api_section');
        if (analysisApi && customApiSection) {
            analysisApi.addEventListener('change', () => customApiSection.style.display = analysisApi.value === 'custom' ? '' : 'none');
        }
        const modelSel = g('search_custom_model_select');
        const modelInp = g('search_custom_model');
        if (modelSel && modelInp) modelSel.addEventListener('change', () => { if (modelSel.value) modelInp.value = modelSel.value; });
        const fetchBtn = g('search_fetch_models_btn');
        if (fetchBtn) fetchBtn.addEventListener('click', async () => { saveSettings(readSettingsFromPanel(doc)); await fetchModelsFromCustomApi(); });
        const presetMode = g('search_preset_mode');
        const presetSection = g('search_preset_section');
        const builtinHint = g('search_builtin_hint');
        if (presetMode && presetSection) {
            presetMode.addEventListener('change', () => {
                presetSection.style.display = presetMode.value === 'other' ? '' : 'none';
                if (builtinHint) builtinHint.style.display = presetMode.value === 'builtin' ? '' : 'none';
            });
        }
        const refreshPresets = g('search_refresh_presets_btn');
        if (refreshPresets) refreshPresets.addEventListener('click', () => { saveSettings(readSettingsFromPanel(doc)); mounted = false; renderSettingsPanel(true); });
        const testPreset = g('search_test_preset_btn');
        if (testPreset) testPreset.addEventListener('click', () => {
            try {
                const s = saveSettings(readSettingsFromPanel(doc));
                if (!s.searchPresetName) { toast('未选择预设', 'warning'); return; }
                getPresetObject(s.searchPresetName);
                toast(`预设读取成功：${s.searchPresetName}`, 'success');
            } catch (e) { toast('预设读取失败', 'error'); }
        });
        const saveBtn = g('search_save_btn');
        if (saveBtn) saveBtn.addEventListener('click', () => { saveSettings(readSettingsFromPanel(doc)); toast('已保存', 'success'); });
        const manualBtn = g('search_manual_btn');
        if (manualBtn) manualBtn.addEventListener('click', async () => {
            saveSettings(readSettingsFromPanel(doc));
            const lastId = getFn('getLastMessageId')?.();
            if (lastId == null) { toast('无法获取楼层', 'error'); return; }
            await manualSearchFlow(lastId);
        });
        const testBtn = g('search_test_btn');
        if (testBtn) testBtn.addEventListener('click', () => { saveSettings(readSettingsFromPanel(doc)); toast('面板正常', 'info'); });
        const resetBtn = g('search_reset_btn');
        if (resetBtn) resetBtn.addEventListener('click', () => { runtimeModelList = []; saveSettings({ ...defaultSettings }); mounted = false; renderSettingsPanel(true); toast('已恢复默认', 'success'); });
        const refreshInj = g('injection_refresh_btn');
        if (refreshInj) refreshInj.addEventListener('click', () => { refreshInjectionManager(); toast('已刷新', 'info'); });
        const saveInj = g('injection_save_btn');
        if (saveInj) saveInj.addEventListener('click', async () => {
            const ta = g('injection_manager_textarea');
            if (!ta?.value.trim()) { toast('内容为空', 'warning'); return; }
            await injectCustomContent(ta.value);
        });
        const clearInj = g('injection_clear_btn');
        if (clearInj) clearInj.addEventListener('click', () => clearSearchInjection());
        setTimeout(() => refreshInjectionManager(), 200);
    }

    function renderSettingsPanel(force = false) {
        if (mounted && !force) return true;
        const doc = findTargetDocument();
        const container = ensureContainer(doc);
        if (!container) { retryMount(); return false; }
        injectStyle(doc);
        const s = loadSettings();
        if (s.searchPresetMode === 'other') {
            const names = getPresetNames();
            if (names.length && !names.includes(s.searchPresetName)) { s.searchPresetName = names[0]; saveSettings(s); }
        }
        container.innerHTML = getPanelHtml(s);
        bindPanelEvents(doc);
        mounted = true;
        return true;
    }

    function retryMount() {
        if (mounted || retryTimer) return;
        if (++retryCount > MAX_RETRY) return;
        retryTimer = setTimeout(() => { retryTimer = null; renderSettingsPanel(); }, 1000);
    }

    function observeSettingsRoot() {
        for (const doc of getDocumentCandidates()) {
            try { new MutationObserver(() => { if (!mounted) renderSettingsPanel(); }).observe(doc.body, { childList: true, subtree: true }); } catch {}
        }
    }

    function init() {
        registerSearchListeners();
        registerQuickButtons();
        renderSettingsPanel();
        observeSettingsRoot();
        for (const t of [1000, 3000, 5000]) setTimeout(() => renderSettingsPanel(), t);
        toast('狐搜已加载', 'success');
    }

    document.readyState === 'loading' ? document.addEventListener('DOMContentLoaded', init) : init();

    window.husouMountPanel = () => { mounted = false; return renderSettingsPanel(true); };
    window.husouGetSettings = loadSettings;
    window.husouClearInjection = clearSearchInjection;
    window.husouToggle = toggleAutoSearch;
    window.husouManualSearch = async () => {
        const lastId = getFn('getLastMessageId')?.();
        if (lastId == null) { toast('无法获取楼层', 'error'); return; }
        lastHandledMessageId = null;
        await manualSearchFlow(lastId);
    };
})();

