        { id: 'world_building', identifier: '7f8fcef1-8385-41ba-a963-fe57bed0c3d4', label: '世界观/设定', icon: '🌍', guide: '你对世界观设定的详细程度有什么要求？需要大量背景还是点到为止？' },
        { id: 'no_go', identifier: '1455cd12-2848-47b3-a4d1-539f042cd392', label: '雷区', icon: '🚫', guide: '有没有绝对不能出现的内容？请列出，AI 会严格避免。' },
        { id: 'user_traits', identifier: 'd26954c8-4cdc-42e4-a551-98e4a34a30ce', label: '用户角色形象', icon: '🧑‍🎨', guide: '综合以上所有偏好，你希望自己扮演的角色应该是什么形象？需要具备什么样的特质？（此模块会综合前面所有分析结果 + 你的额外输入来生成）', isComposite: true },
    ];

    const defaultSettings = {
        firstRun: true,
        analyzed: {},
        drafts: {},
    };

    let settings = loadSettings();
    let isAnalyzing = false; // 全局分析锁，确保同一时间只有一个分析请求
    let mounted = false;
    let retryTimer = null;
    let retryCount = 0;
    const MAX_RETRY = 60;

    // ===================== 工具函数 =====================
    function log(...args) { console.log(`[${SCRIPT_NAME}]`, ...args); }

    function escapeHtml(str) {
        return String(str ?? '').replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;').replace(/"/g, '&quot;');
    }

    function loadSettings() {
        try {
            const raw = localStorage.getItem(STORAGE_KEY);
            return raw ? { ...defaultSettings, ...JSON.parse(raw) } : { ...defaultSettings };
        } catch { return { ...defaultSettings }; }
    }

    function saveSettings() {
        localStorage.setItem(STORAGE_KEY, JSON.stringify(settings));
    }

    function getDocumentCandidates() {
        const docs = [];
        try { if (window.document) docs.push(window.document); } catch {}
        try { if (window.parent?.document && !docs.includes(window.parent.document)) docs.push(window.parent.document); } catch {}
        try { if (window.top?.document && !docs.includes(window.top.document)) docs.push(window.top.document); } catch {}
        return docs;
    }

    function findTargetDocument() {
        for (const doc of getDocumentCandidates()) {
            try {
                if (doc.getElementById(CONTAINER_ID)) return doc;
                if (doc.getElementById('extensions_settings2')) return doc;
            } catch {}
        }
        return document;
    }

    function ensureContainer(doc) {
        let container = doc.getElementById(CONTAINER_ID);
        if (container) return container;
        const settingsRoot = doc.getElementById('extensions_settings2');
        if (!settingsRoot) return null;
        container = doc.createElement('div');
        container.id = CONTAINER_ID;
        container.className = 'extension_container';
        settingsRoot.appendChild(container);
        return container;
    }

    function getST() {
        return window.SillyTavern || window.parent?.SillyTavern || window.top?.SillyTavern;
    }

    function getSTWindow() {
        const candidates = [];
        try { candidates.push(window); } catch {}
        try { candidates.push(window.parent); } catch {}
        try { candidates.push(window.top); } catch {}
        for (const win of candidates) {
            try {
                if (!win) continue;
                if (win.SillyTavern) return win;
                if (typeof win.generate === 'function') return win;
            } catch {}
        }
        return window;
    }

    function getFn(name) { return getSTWindow()?.[name] || window?.[name]; }

    function toast(message, type = 'info') {
        try {
            const t = getSTWindow()?.toastr || window.toastr;
            if (t && t[type]) t[type](message, SCRIPT_NAME);
        } catch {}
    }

    // ===================== 预设操作 =====================
    function getPromptsArray() {
        try {
            const st = getST();
            if (!st?.getContext) return null;
            const ctx = st.getContext();
            return ctx?.chatCompletionSettings?.prompts || null;
        } catch (e) {
            return null;
        }
    }

    function savePrompts() {
        try {
            const st = getST();
            if (!st?.getContext) return;
            const ctx = st.getContext();
            if (ctx?.saveSettingsDebounced) {
                ctx.saveSettingsDebounced();
            }
        } catch (e) {
            log('保存预设失败', e);
        }
    }

    function findPromptByIdentifier(identifier) {
        const prompts = getPromptsArray();
        if (!prompts) return null;
        return prompts.find(p => p?.identifier === identifier) || null;
    }

    function injectUserPrefEntry(identifier, content, moduleLabel) {
        const existing = findPromptByIdentifier(identifier);
        if (!existing) {
            toast(`❌ 未找到条目：${identifier}`, 'error');
            log('未找到条目:', identifier);
            return;
        }
        existing.content = content;
        savePrompts();
        toast(`✅ 已写入预设：${moduleLabel}偏好`, 'success');
        log(`已写入: ${moduleLabel}, content长度=${content?.length}`);
    }

    function toggleModulePreference(identifier, enable, moduleLabel) {
        const existing = findPromptByIdentifier(identifier);
        if (!existing) {
            toast(`❌ 未找到条目`, 'error');
            return;
        }
        existing.enabled = enable;
        savePrompts();
        toast(`✅ ${enable ? '已启用' : '已关闭'}：${moduleLabel}偏好`, 'success');
    }

    function toggleAllPreferences(enable) {
        const prompts = getPromptsArray();
        if (!prompts) {
            toast('❌ 无法读取预设', 'error');
            return;
        }
        let foundAny = false;
        for (const prompt of prompts) {
            if (!prompt) continue;
            const isUserPref = MODULES.some(m => m.identifier === prompt.identifier);
            if (isUserPref) {
                prompt.enabled = enable;
                foundAny = true;
            }
        }
        savePrompts();
        if (foundAny) {
            toast(`✅ ${enable ? '已启用全部用户偏好' : '已关闭全部用户偏好'}`, 'success');
        } else {
            toast('⚠️ 未找到任何用户偏好条目', 'warning');
        }
    }

    function clearModulePreference(identifier, moduleLabel) {
        const existing = findPromptByIdentifier(identifier);
        if (!existing) {
            toast(`❌ 未找到条目`, 'error');
            return;
        }
        existing.content = '';
        existing.enabled = false;
        savePrompts();
        toast(`🗑️ 已清除：${moduleLabel}偏好`, 'success');
    }

    function clearAllPreferences() {
        const prompts = getPromptsArray();
        if (!prompts) {
            toast('❌ 无法读取预设', 'error');
            return;
        }
        let foundAny = false;
        for (const prompt of prompts) {
            if (!prompt) continue;
            const isUserPref = MODULES.some(m => m.identifier === prompt.identifier);
            if (isUserPref) {
                prompt.content = '';
                prompt.enabled = false;
                foundAny = true;
            }
        }
        savePrompts();
        if (foundAny) {
            toast('⚠️ 已清除所有用户偏好注入', 'success');
        } else {
            toast('⚠️ 未找到任何用户偏好条目', 'warning');
        }
    }

    function getPreferenceStates() {
        const states = {};
        for (const mod of MODULES) {
            const entry = findPromptByIdentifier(mod.identifier);
            states[mod.id] = entry?.enabled === true;
        }
        return states;
    }

    // ===================== AI 分析 =====================
    async function analyzeModule(moduleId, userInput) {
        const module = MODULES.find(m => m.id === moduleId);
        if (!userInput?.trim()) return null;

        // 等待锁释放（同一时间只允许一个分析请求）
        while (isAnalyzing) {
            await new Promise(r => setTimeout(r, 200));
        }
        isAnalyzing = true;

        let system, user;

        if (module.isComposite) {
            const previousResults = [];
            for (const mod of MODULES) {
                if (mod.isComposite) continue;
                const analyzed = settings.analyzed[mod.id];
                if (analyzed?.trim()) {
                    previousResults.push(`【${mod.label}】${analyzed}`);
                }
            }
            system = `你是用户画像深度分析师。请根据用户的所有偏好分析结果和额外输入，详细描绘用户角色或对应特征应该具备的核心特质。要求：丰富、具体、有层次感。分点描述，每条展开说明原因和具体表现，要详细，准确。不低于100字`;
            user = `已有偏好分析结果：\n${previousResults.join('\n') || '（暂无其他模块的分析结果）'}\n\n用户额外输入：\n${userInput}\n\n请综合以上信息，详细描绘用户角色需要具备的特质：`;
        } else {
            system = `你是用户偏好分析师。请阅读用户对"${module.label}"的简要回答，将其展开为一份精准的偏好分析。

格式要求：
- 提炼出1-3个核心要点，每个要点用 *简短标题*：开头
- 每个要点只写1-2句具体说明，直接概括其要点，不要废话
- 语言精准、有洞察力
- 总字数100-250字

格式参考：
 *要点一*：具体说明，一两句。
 *要点二*：具体说明，一两句。

不要添加开场白、总结语、或任何超出要点的内容。`;
            user = `用户对"${module.label}"的回答：\n${userInput}\n\n请将以上简要回答拓展为精确、准确的偏好描述（分点展开，给出具体示例）：`;
        }

        try {
            const generateRaw = getFn('generateRaw');
            if (typeof generateRaw !== 'function') throw new Error('无 generateRaw 接口');

            const result = await generateRaw({
                user_input: user,
                should_silence: true,
                should_stream: false,
                max_chat_history: 0,
                ordered_prompts: [
                    { role: 'system', content: system },
                    'user_input',
                ],
            });
            const text = typeof result === 'string' ? result : result?.content || '';
            return text.trim();
        } catch (e) {
            log('AI 分析失败', e);
            throw e;
        } finally {
            isAnalyzing = false; // 无论成功失败，释放锁
        }
    }

    // ===================== UI 构建 =====================
    function buildModuleHtml(module) {
        // 优先从预设条目读取 content，其次从 settings.analyzed
        const entry = findPromptByIdentifier(module.identifier);
        const presetContent = entry?.content || '';
        const analyzed = settings.analyzed[module.id] || presetContent || '';
        const draft = settings.drafts[module.id] || '';
        const guideExtra = module.isComposite
            ? '<br><span style="color:#e07b3c;">⚠️ 此模块会综合前面所有模块的分析结果 + 你的额外输入来生成，建议先分析其他模块。</span>'
            : '';

        return `
        <div class="inline-drawer hushen-module" data-module="${module.id}">
            <div class="inline-drawer-toggle inline-drawer-header">
                <b>${module.icon} ${module.label}偏好</b>
                <div class="inline-drawer-icon fa-solid fa-circle-chevron-down down"></div>
            </div>
            <div class="inline-drawer-content">
                <div class="hushen_setting_block">
                    <div class="hushen_hint">${module.guide}${guideExtra}</div>
                    <textarea class="hushen-input text_pole" placeholder="写下你的偏好..." rows="4">${escapeHtml(draft)}</textarea>
                    <div class="flex-container" style="gap:8px;margin-top:8px;">
                        <input class="hushen-analyze-btn menu_button" type="button" value="🔍 分析当前模块">
                        <input class="hushen-toggle-btn menu_button" type="button" value="🔘 切换为此偏好">
                    </div>
                    <div class="hushen_subtitle">📝 分析结果（可编辑）</div>
                    <textarea class="hushen-result-text text_pole" placeholder="分析结果会显示在这里..." rows="3">${escapeHtml(analyzed)}</textarea>
                    <div class="flex-container" style="gap:8px;margin-top:8px;">
                        <input class="hushen-save-btn menu_button" type="button" value="💾 保存修改到预设">
                        <input class="hushen-clear-btn menu_button" type="button" value="🗑️ 清除此模块">
                    </div>
                </div>
            </div>
        </div>`;
    }

    function buildPanelHtml() {
        let html = `
        <div id="${PANEL_ID}" class="inline-drawer">
            <div class="inline-drawer-toggle inline-drawer-header">
                <b>🦊 狐析~</b>
                <div class="inline-drawer-icon fa-solid fa-circle-chevron-down down"></div>
            </div>
            <div class="inline-drawer-content">
                <div class="hushen_setting_block">
                    <div class="hushen_hint">
                        🦊 对我的设定不满意吗？哼...真挑剔呢~   (｡•́-•̀｡) 
                              既然这样……那就由你自己来写吧，诺，自己看下面...( ＿ ＿)ノ｜：<br>
                        （分析结果会注入到预设提示词，默认不启用，你可以手动切换。）
                    </div>
                </div>`;

        for (const mod of MODULES) {
            html += buildModuleHtml(mod);
        }

        html += `
                <div class="hushen_setting_block">
                    <div class="hushen_subtitle">全局操作</div>
                    <div class="flex-container" style="gap:8px;">
                        <input id="hushen_analyze_all" class="menu_button" type="button" value="⚡ 一键分析所有已填写模块">
                        <input id="hushen_toggle_all" class="menu_button" type="button" value="📋 加载全部用户偏好">
                        <input id="hushen_clear_all" class="menu_button" type="button" value="⚠️ 一键清除所有注入" style="background:#8b0000;border-color:#8b0000;">
                    </div>
                    <div id="hushen_status" class="hushen_status"></div>
                </div>
            </div>
        </div>`;
        return html;
    }

    function injectStyle(doc) {
        if (doc.getElementById('hushen_profile_style')) return;
        const s = doc.createElement('style');
        s.id = 'hushen_profile_style';
        s.textContent = `
            #${PANEL_ID} .hushen_setting_block { padding: 8px 0; }
            #${PANEL_ID} .hushen_hint { opacity: 0.75; font-size: 0.9em; margin: 4px 0 8px; }
            #${PANEL_ID} .hushen_subtitle { font-weight: bold; margin-top: 12px; margin-bottom: 6px; }
            #${PANEL_ID} .hushen_status { margin-top: 8px; opacity: 0.8; font-size: 0.9em; }
            #${PANEL_ID} .hushen-module { margin-bottom: 4px; }
            #${PANEL_ID} .hushen-input:focus,
            #${PANEL_ID} .hushen-result-text:focus { border-color: #e07b3c !important; }
        `;
        doc.head.appendChild(s);
    }

    // ===================== 事件绑定 =====================
    function bindPanelEvents(doc) {
        // 分析单个模块
        doc.querySelectorAll('.hushen-analyze-btn').forEach(btn => {
            btn.addEventListener('click', async function() {
                const moduleDiv = this.closest('.hushen-module');
                const moduleId = moduleDiv.dataset.module;
                const module = MODULES.find(m => m.id === moduleId);
                const textarea = moduleDiv.querySelector('.hushen-input');
                const resultArea = moduleDiv.querySelector('.hushen-result-text');
                const userInput = textarea.value.trim();

                if (!userInput) {
                    toast('⚠️ 请先填写内容再分析', 'warning');
                    return;
                }

                settings.drafts[moduleId] = userInput;
                saveSettings();

                this.value = '⏳ 分析中...';
                this.disabled = true;
                toast(`🔍 正在分析「${module.label}」...`, 'info');

                try {
                    const analyzed = await analyzeModule(moduleId, userInput);
                    this.value = '🔍 分析当前模块';
                    this.disabled = false;

                    if (analyzed) {
                        resultArea.value = analyzed;
                        settings.analyzed[moduleId] = analyzed;
                        saveSettings();
                        injectUserPrefEntry(module.identifier, analyzed, module.label);
                        updateToggleButtonStates(doc);
                    } else {
                        toast('❌ 分析返回空结果，请重试', 'error');
                    }
                } catch (e) {
                    this.value = '🔍 分析当前模块';
                    this.disabled = false;
                    toast(`❌ 分析失败：${e.message}`, 'error');
                }
            });
        });

        // 保存修改
        doc.querySelectorAll('.hushen-save-btn').forEach(btn => {
            btn.addEventListener('click', function() {
                const moduleDiv = this.closest('.hushen-module');
                const moduleId = moduleDiv.dataset.module;
                const module = MODULES.find(m => m.id === moduleId);
                const resultArea = moduleDiv.querySelector('.hushen-result-text');
                const newContent = resultArea.value.trim();

                if (!newContent) {
                    toast('⚠️ 内容为空，未保存', 'warning');
                    return;
                }

                settings.analyzed[moduleId] = newContent;
                saveSettings();
                injectUserPrefEntry(module.identifier, newContent, module.label);
                updateToggleButtonStates(doc);
            });
        });

        // 切换单个模块偏好
        doc.querySelectorAll('.hushen-toggle-btn').forEach(btn => {
            btn.addEventListener('click', function() {
                const moduleDiv = this.closest('.hushen-module');
                const moduleId = moduleDiv.dataset.module;
                const module = MODULES.find(m => m.id === moduleId);
                const states = getPreferenceStates();
                const currentlyEnabled = states[moduleId] || false;

                toggleModulePreference(module.identifier, !currentlyEnabled, module.label);
                updateToggleButtonStates(doc);
            });
        });

        // 清除单个模块
        doc.querySelectorAll('.hushen-clear-btn').forEach(btn => {
            btn.addEventListener('click', function() {
                const moduleDiv = this.closest('.hushen-module');
                const moduleId = moduleDiv.dataset.module;
                const module = MODULES.find(m => m.id === moduleId);
                const textarea = moduleDiv.querySelector('.hushen-input');
                const resultArea = moduleDiv.querySelector('.hushen-result-text');

                // 清空面板
                textarea.value = '';
                resultArea.value = '';
                delete settings.drafts[moduleId];
                delete settings.analyzed[moduleId];
                saveSettings();

                // 清空预设
                clearModulePreference(module.identifier, module.label);
                updateToggleButtonStates(doc);
            });
        });

        // 一键分析全部
        const analyzeAllBtn = doc.getElementById('hushen_analyze_all');
        if (analyzeAllBtn) {
            analyzeAllBtn.addEventListener('click', async function() {
                const modules = doc.querySelectorAll('.hushen-module');
                let filledCount = 0;
                let successCount = 0;

                this.value = '⏳ 分析中...';
                this.disabled = true;
                toast('⚡ 开始逐个分析...', 'info');

                // 先分析非综合模块，再分析综合模块
                const sortedModules = [...modules].sort((a, b) => {
                    const modA = MODULES.find(m => m.id === a.dataset.module);
                    const modB = MODULES.find(m => m.id === b.dataset.module);
                    if (modA?.isComposite) return 1;
                    if (modB?.isComposite) return -1;
                    return 0;
                });

                for (const modDiv of sortedModules) {
                    const moduleId = modDiv.dataset.module;
                    const module = MODULES.find(m => m.id === moduleId);
                    const textarea = modDiv.querySelector('.hushen-input');
                    const userInput = textarea.value.trim();

                    if (!userInput) continue;
                    filledCount++;

                    settings.drafts[moduleId] = userInput;

                    try {
                        const resultArea = modDiv.querySelector('.hushen-result-text');
                        this.value = `⏳ 分析中 (${filledCount})...`;

                        const analyzed = await analyzeModule(moduleId, userInput);

                        if (analyzed) {
                            resultArea.value = analyzed;
                            settings.analyzed[moduleId] = analyzed;
                            injectUserPrefEntry(module.identifier, analyzed, module.label);
                            successCount++;
                        }
                    } catch (e) {
                        log(`模块 ${module.label} 分析失败`, e);
                        toast(`❌ 「${module.label}」分析失败，继续下一个...`, 'error');
                    }
                }

                saveSettings();
                this.value = '⚡ 一键分析所有已填写模块';
                this.disabled = false;

                if (filledCount === 0) {
                    toast('⚠️ 没有填写任何模块，请至少填写一个', 'warning');
                } else {
                    toast(`✅ 分析完成：${successCount}/${filledCount} 个模块成功`, successCount === filledCount ? 'success' : 'warning');
                }
                updateToggleButtonStates(doc);
            });
        }

        // 全部偏好开关
        let allEnabled = false;
        const toggleAllBtn = doc.getElementById('hushen_toggle_all');
        if (toggleAllBtn) {
            toggleAllBtn.addEventListener('click', function() {
                allEnabled = !allEnabled;
                toggleAllPreferences(allEnabled);
                this.value = allEnabled ? '📋 关闭全部用户偏好' : '📋 加载全部用户偏好';
                updateToggleButtonStates(doc);
            });
        }

        // 一键清除全部
        const clearAllBtn = doc.getElementById('hushen_clear_all');
        if (clearAllBtn) {
            clearAllBtn.addEventListener('click', function() {
                if (!confirm('⚠️ 确定要清除所有用户偏好注入吗？此操作不可恢复！')) return;

                // 清空所有面板
                doc.querySelectorAll('.hushen-module').forEach(modDiv => {
                    modDiv.querySelector('.hushen-input').value = '';
                    modDiv.querySelector('.hushen-result-text').value = '';
                });

                // 清空本地存储
                settings.drafts = {};
                settings.analyzed = {};
                saveSettings();

                // 清空预设
                clearAllPreferences();
                updateToggleButtonStates(doc);
            });
        }

        updateToggleButtonStates(doc);
    }

    function updateToggleButtonStates(doc) {
        const states = getPreferenceStates();
        doc.querySelectorAll('.hushen-toggle-btn').forEach(btn => {
            const moduleDiv = btn.closest('.hushen-module');
            const moduleId = moduleDiv.dataset.module;
            btn.value = states[moduleId] ? '🔘 恢复默认' : '🔘 切换为此偏好';
        });

        const statusEl = doc.getElementById('hushen_status');
        if (statusEl) {
            const enabledModules = Object.entries(states).filter(([, v]) => v).length;
            statusEl.textContent = `当前状态：${enabledModules}/${MODULES.length} 个模块正在使用用户偏好`;
        }
    }

    // ===================== 渲染与挂载 =====================
    function renderSettingsPanel(force = false) {
        if (mounted && !force) return true;

        const doc = findTargetDocument();
        const container = ensureContainer(doc);
        if (!container) {
            retryMount();
            return false;
        }

        injectStyle(doc);
        container.innerHTML = buildPanelHtml();
        bindPanelEvents(doc);
        mounted = true;
        log('面板渲染成功');
        return true;
    }

    function retryMount() {
        if (mounted || retryTimer) return;
        if (++retryCount > MAX_RETRY) return;
        retryTimer = setTimeout(() => {
            retryTimer = null;
            renderSettingsPanel();
        }, 1000);
    }

    function observeSettingsRoot() {
        for (const doc of getDocumentCandidates()) {
            try {
                new MutationObserver(() => {
                    if (!mounted) renderSettingsPanel();
                }).observe(doc.body, { childList: true, subtree: true });
            } catch {}
        }
    }

    function init() {
        renderSettingsPanel();
        observeSettingsRoot();

        for (const t of [500, 1500, 3000]) {
            setTimeout(() => renderSettingsPanel(), t);
        }

        if (settings.firstRun) {
            setTimeout(() => {
                toast('🦊 狐析已加载！点击扩展面板进行用户偏好配置（可选，不配置也能直接使用）', 'info');
            }, 2000);
            settings.firstRun = false;
            saveSettings();
        }

        log('脚本初始化完成');
    }

    if (document.readyState === 'loading') {
        document.addEventListener('DOMContentLoaded', init);
    } else {
        init();
    }

    window.hushenProfileMountPanel = () => {
        mounted = false;
        return renderSettingsPanel(true);
    };
})();

