    (function() {
      const thoughtChain = document.getElementById('thoughtChain');
      const chainHeader = document.getElementById('chainHeader');
      const chainContent = document.getElementById('chainContent');
      const chainFooterToggle = document.getElementById('chainFooterToggle');
      const themeToggleBtn = document.getElementById('themeToggleBtn');
      const particleLayer = document.getElementById('particleLayer');
      const body = document.body;
      let isExpanded = false;

      function toggleChain(event) {
        if (event) event.stopPropagation();
        if (isExpanded) {
          thoughtChain.classList.remove('expanded');
          chainContent.style.maxHeight = '0';
          isExpanded = false;
          chainHeader.setAttribute('aria-expanded', 'false');
          chainFooterToggle.textContent = '展开 ▼';
        } else {
          thoughtChain.classList.add('expanded');
          chainContent.style.maxHeight = chainContent.scrollHeight + 'px';
          isExpanded = true;
          chainHeader.setAttribute('aria-expanded', 'true');
          chainFooterToggle.textContent = '收起 ▲';
        }
      }

      chainHeader.addEventListener('click', toggleChain);
      chainFooterToggle.addEventListener('click', toggleChain);

      chainHeader.addEventListener('keydown', function(e) {
        if (e.key === 'Enter' || e.key === ' ') {
          e.preventDefault();
          toggleChain(e);
        }
      });

      function applyTheme(theme) {
        if (theme === 'light') {
          body.classList.add('light-theme');
          body.classList.remove('dark-theme');
          localStorage.setItem('fox-preset-theme', 'light');
        } else {
          body.classList.remove('light-theme');
          body.classList.add('dark-theme');
          localStorage.setItem('fox-preset-theme', 'dark');
        }
      }

      const storedTheme = localStorage.getItem('fox-preset-theme');
      if (storedTheme === 'light' || storedTheme === 'day') {
        applyTheme('light');
      } else if (storedTheme === 'dark' || storedTheme === 'night') {
        applyTheme('dark');
      } else {
        applyTheme('dark');
      }

      themeToggleBtn.addEventListener('click', function(e) {
        e.stopPropagation();
        if (body.classList.contains('light-theme')) {
          applyTheme('dark');
        } else {
          applyTheme('light');
        }
      });

      // 粒子
      function rr(a, b) { return a + Math.random() * (b - a); }
      const configs = [
        { cls: 'gd', n: 8, w: [2, 5], h: [2, 5], dur: [4, 9] },
        { cls: 'lr', n: 3, w: [1, 1], h: [35, 70], dur: [5, 10] }
      ];
      for (let gi = 0; gi < configs.length; gi++) {
        const g = configs[gi];
        for (let pi = 0; pi < g.n; pi++) {
          const p = document.createElement('div');
          p.className = 'ax-p ' + g.cls;
          p.style.width = rr(g.w[0], g.w[1]) + 'px';
          p.style.height = rr(g.h[0], g.h[1]) + 'px';
          p.style.left = (Math.random() * 90 + 5) + '%';
          p.style.top = (Math.random() * 90 + 5) + '%';
          if (g.cls === 'gd') {
            p.style.borderRadius = '50%';
            p.style.background = 'radial-gradient(circle, rgba(200, 200, 210, 0.35), rgba(160, 160, 170, 0.08), transparent)';
            p.style.animation = 'ascParticle ' + rr(g.dur[0], g.dur[1]) + 's ease-in-out infinite';
          } else {
            p.style.background = 'linear-gradient(180deg, rgba(200, 200, 210, 0.2), rgba(200, 200, 210, 0.04), transparent)';
            p.style.animation = 'pulseVertical ' + rr(g.dur[0], g.dur[1]) + 's ease-in-out infinite';
            p.style.transformOrigin = 'top center';
          }
          p.style.animationDelay = -(Math.random() * 35) + 's';
          p.style.setProperty('--po', (0.15 + Math.random() * 0.2).toFixed(2));
          particleLayer.appendChild(p);
        }
      }

      // 默认折叠
      chainContent.style.maxHeight = '0';
      chainHeader.setAttribute('aria-expanded', 'false');
    })();
  </script>
